\label{l:lemma uniqueness minimal lie core} Let $G$ be a locally compact topological group and $(K_1,H_1)$ and $(K_2,H_2)$ two minimal Yamabe pairs with Lie cores $\pi_1\coloneqq \pi_{H_1/K_1}:\ H_1\rightarrow L_1$ and $\pi_2\coloneqq \pi_{H_2/K_2}:\ H_2\rightarrow L_2$:
\begin{enumerate}[label={\rm{(\arabic*)}}, ref={\rm{\arabic*}}, wide]
\item \label{itm:lemma uniqueness minimal lie core:reduce domain} Let $H'\leq H_1$ be an open subgroup. Then, $(K_1\cap H',H')$ is a minimal Yamabe pair of $G$ equivalent to $(K_1,H_1)$ and $[K_1:K_1\cap H']$ is finite.
\item \label{itm:lemma uniqueness minimal lie core:smaller kernel} $K_1\subseteq K_2\Leftrightarrow H_1\subseteq H_2\Leftrightarrow K_2\cap H_1=K_1$. In particular, $K_1=K_2$ if and only if $H_1=H_2$.
\item \label{itm:lemma uniqueness minimal lie core:intersection} $(K_1\cap K_2,H_1\cap H_2)$ is a minimal Yamabe pair with $K_1\cap H_2=K_1\cap K_2=K_2\cap H_1$. In particular, $[K_1:K_1\cap K_2]$ and $[K_2:K_1\cap K_2]$ are finite.
\end{enumerate}
\begin{proof}
\begin{enumerate}[label={\rm{(\arabic*)}}, wide]
\item[\hspace{-1.6em}\setcounter{enumi}{1}\theenumi] By connectedness, $\pi_1[H']=L_1$. Thus, by the Closed Isomorphism Theorem (\cref{o:remarks topological groups}(\ref{itm:remarks topological groups:closed isomorphism theorem})), we conclude that $(K_1\cap H',H')$ is a minimal Yamabe pair of $G$ equivalent to $(K_1,H_1)$. Finally, as $K_1\cap H'$ is an open subset of $K_1$, by compactness, $[K_1:K_1\cap H']$ is finite.
\item We already have $H_1\subseteq H_2\Rightarrow K_2\cap H_1=K_1\Rightarrow K_1\subseteq K_2$ by the previous point (\ref*{itm:lemma uniqueness minimal lie core:reduce domain}). On the other hand, by connectedness, $\pi_1[H_1\cap H_2]=L_1$. If $K_1\subseteq K_2$, then $K_1\leq H_1\cap H_2$, so $H_1=\pi^{-1}_1[\pi_1[H_1\cap H_2]]=H_1\cap H_2\subseteq H_2$.
\item By point (\ref*{itm:lemma uniqueness minimal lie core:reduce domain}), $(K_1\cap H_2,H_1\cap H_2)$ and $(K_2\cap H_1,H_2\cap H_1)$ are minimal Yamabe pairs with $[K_1:K_1\cap H_2]$ and $[K_2:H_1\cap K_2]$ finite. By point (\ref*{itm:lemma uniqueness minimal lie core:smaller kernel}), $K_1\cap K_2=K_1\cap H_2=K_2\cap H_1$. \qedhere
\end{enumerate}
\end{proof}

